import React from "react";
import "../styles/nav-ul.css";

function NavUl(props) {
  return (
    <div className="nav__ul-contenedor">
      <ul className="nav__ul">
        <li className="nav__li">
          <a className="nav__a" href="#">
            Conocimientos
          </a>
        </li>
        <li className="nav__li">
          <a className="nav__a" href="#">
            Proyectos
          </a>
        </li>
        <li className="nav__li">
          <a className="nav__a" href="#">
            Contactame
          </a>
        </li>
      </ul>
    </div>
  );
}

export default NavUl;
